import { SUDOKU_SIZE } from '@sudoku/constants';
import { decodeSencode, encodeSudoku } from '@sudoku/sencode';
import { generateSudoku, solveSudoku } from '@sudoku/sudoku';
import { derived, writable } from 'svelte/store';
import { hints } from './hints';
import { createGame, createSudoku } from '../../../domain/index.js';

function emptyGrid() {
	return Array.from({ length: SUDOKU_SIZE }, () => Array(SUDOKU_SIZE).fill(0));
}

function createDomainGameStore() {
	const state = writable({
		game: createGame({ sudoku: createSudoku(emptyGrid()) }),
		puzzleGrid: emptyGrid(),
		userGrid: emptyGrid(),
	});

	function syncGame(storeState, game) {
		const sudoku = game.getSudoku();
		return {
			game,
			puzzleGrid: storeState.puzzleGrid,
			userGrid: sudoku.getGrid(),
		};
	}

	function startWithPuzzle(puzzle) {
		state.update((storeState) => {
			const game = createGame({ sudoku: createSudoku(puzzle) });
			return {
				game,
				puzzleGrid: puzzle.map((row) => row.slice()),
				userGrid: game.getSudoku().getGrid(),
			};
		});
	}

	return {
		subscribe: state.subscribe,
		startWithPuzzle,
		guess(pos, value) {
			state.update((storeState) => {
				if (storeState.puzzleGrid[pos.y][pos.x] !== 0) return storeState;
				storeState.game.guess({ row: pos.y, col: pos.x, value });
				return syncGame(storeState, storeState.game);
			});
		},
		applyHint(pos) {
			hints.useHint();
			state.update((storeState) => {
				if (storeState.puzzleGrid[pos.y][pos.x] !== 0) return storeState;
				const solvedSudoku = solveSudoku(storeState.userGrid);
				storeState.game.guess({ row: pos.y, col: pos.x, value: solvedSudoku[pos.y][pos.x] });
				return syncGame(storeState, storeState.game);
			});
		},
		undo() {
			state.update((storeState) => {
				if (!storeState.game.undo()) return storeState;
				return syncGame(storeState, storeState.game);
			});
		},
		redo() {
			state.update((storeState) => {
				if (!storeState.game.redo()) return storeState;
				return syncGame(storeState, storeState.game);
			});
		},
	};
}

const domainGame = createDomainGameStore();

function createGrid() {
	return {
		subscribe: derived(domainGame, ($domainGame) => $domainGame.puzzleGrid).subscribe,

		generate(difficulty) {
			domainGame.startWithPuzzle(generateSudoku(difficulty));
		},

		decodeSencode(sencode) {
			domainGame.startWithPuzzle(decodeSencode(sencode));
		},

		get(gridStore, x, y) {
			return gridStore[y][x];
		},

		getSencode(gridStore) {
			return encodeSudoku(gridStore);
		},
	};
}

export const grid = createGrid();


function createUserGrid() {
	return {
		subscribe: derived(domainGame, ($domainGame) => $domainGame.userGrid).subscribe,

		set: (pos, value) => {
			domainGame.guess(pos, value);
		},

		applyHint: (pos) => {
			domainGame.applyHint(pos);
		},
		undo: () => domainGame.undo(),
		redo: () => domainGame.redo(),
	};
}

export const userGrid = createUserGrid();

export const invalidCells = derived(domainGame, ($domainGame) => $domainGame.game.getSudoku().getInvalidCells());
export const canUndo = derived(domainGame, ($domainGame) => $domainGame.game.canUndo());
export const canRedo = derived(domainGame, ($domainGame) => $domainGame.game.canRedo());